mapper.delete:
update osh_course_question
set delete_flag = 1
where course_id = #{courseId}

mapper.select:
select id, course_id, section_id, user_id, title, content, solve_status, status, create_time from osh_course_question where course_id = #{courseId}
and section_id = #{sectionId}
and status = #{status}
and delete_flag = 0 order by create_time desc

mapper.update:
update osh_course_question
title = #{title}, content = #{content}, solve_status = #{solveStatus}, status = #{status}, update_by = #{updateBy}, update_time = #{updateTime}
where id = #{id} and delete_flag = 0
